insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (217, 44, 'À votre avis, est-il facile de se faire des amis quand on s''installe dans un nouveau pays ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (222, 45, 'Les immigrés sont une richesse pour un pays. Qu''en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (227, 46, 'Il est nécessaire d''apprendre la langue du pays où l''on vit pour s''intégrer. Êtes-vous d''accord avec cette affirmation? Pourquoi?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (232, 47, 'Pensez-vous qu’il soit plus facile pour les jeunes de vivre à l’étranger ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (237, 48, 'Il est possible de vivre dans un pays sans parler sa langue. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (242, 49, 'Prendre la décision de quitter son pays est facile. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (247, 50, 'Vivre dans un pays étranger est difficile. Êtes-vous d’accord ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (252, 51, 'L''immigration est bénéfique pour les pays d''accueil. Qu''en pensez-vous ?', '', 'fr');
