insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (277, 56, 'Lorsque l''on vit dans un pays étranger, il faut fréquenter des gens de son pays d''origine. Qu''en pensez-vous?', '', 'fr');
