insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (292, 59, 'À votre avis, tout le monde est-il capable de s’adapter dans un pays étranger ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (297, 60, 'A votre Avis, comment un état peut-il faciliter l''intégration des étrangers ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (302, 61, 'Selon vous, un monde sans frontière, ni passeport, ni visa est-il possible ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (307, 62, 'Est-il possible d’avoir un monde sans frontières, sans passeport ni visa ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (312, 63, 'Pour bien s’intégrer dans un pays, il faut renoncer à ses traditions. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (317, 64, 'Pour bien s’intégrer dans un nouveau pays, faudrait-il renoncer à ses traditions ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (322, 65, 'Selon vous, quelles sont les trois questions importantes à se poser avant de commencer des démarches d''immigration au Québec? Pourquoi ces trois là ?', '', 'fr');
