insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (332, 67, 'Il n''y a pas d''âge pour s''intégrer dans un pays d''accueil. Êtes-vous d''accord avec cette affirmation ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (337, 68, 'Il est indispensable de savoir parler anglais quand on voyage à l’étranger. Qu’en pensez-vous ?', '', 'fr');
