insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (412, 83, 'Vivre à l’étranger représente un véritable défi pour beaucoup de personnes. Partagez-vous cette idée ? Expliquez pourquoi.', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (417, 84, 'Pensez-vous que les immigrés contribuent positivement à la richesse d’un pays ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (422, 85, 'Vivre à l’étranger représente-t-il un défi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (427, 86, 'Pensez-vous que chacun a la capacité de s’intégrer et de s’adapter en vivant à l’étranger ? Pourquoi ?', '', 'fr');
