insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (452, 91, 'Pensez-vous que maîtriser la langue du pays où l’on vit soit essentiel pour bien s’intégrer ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (457, 92, 'Pensez-vous que l’intégration dans un nouveau pays est plus simple pour les jeunes ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (462, 93, 'Quand est-il préférable de s’expatrier ? Donnez votre opinion .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (467, 94, 'Partir de son pays pour s’installer à l’étranger est souvent un choix imposé. Qu’en pensez-vous ?', '', 'fr');
