insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (682, 137, 'Travailler jusqu’à 70 ans, Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (687, 138, 'Que pensez-vous de l''idée de travailler jusqu''à 70 ans ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (692, 139, 'Pensez-vous que travailler jusqu’à 70 ans est une bonne idée ?', '', 'fr');
