insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1377, 276, 'Pensez-vous qu''il est important, de nos jours, que les enfants et les adolescents possèdent leur propre téléphone portable ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1382, 277, 'Doit-on empêcher les enfants d’utiliser un téléphone ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1387, 278, 'Le rôle principal de l’école est d’apprendre les matières scolaires. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1392, 279, 'Pensez-vous que la performance à l’école influence le succès dans la vie ?', '', 'fr');
