insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1402, 281, 'Pensez-vous qu’il est acceptable de ne pas vouloir avoir d’enfants ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1407, 282, 'Les jeunes peuvent-ils apprendre facilement une langue étrangère ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1412, 283, 'À votre avis, les jeunes réussissent-ils facilement à maîtriser une langue étrangère ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1417, 284, 'Quelles matières l’école devrait-elle proposer pour rendre les cours plus intéressants pour les élèves ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1422, 285, 'Quel cours préfériez-vous à l’école et pourquoi l’appréciiez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1427, 286, 'Quelle était votre matière préférée à l’école et pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1432, 287, 'D’après vous, quelles matières seraient importantes à enseigner davantage à l’école et pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1437, 288, 'La diversité sociale et culturelle à l''école favorise-t-elle l''esprit de tolérance chez les élèves ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1442, 289, 'Est-il nécessaire que les organisations fournissent des opportunités d''apprentissage régulières à leur personnel ? Cet accès est-il profitable à l''individu ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1447, 290, 'Que pensez-vous des gens qui décident de ne jamais regarder la télévision ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1452, 291, 'Est-il mieux d’apprendre une langue étrangère dès l’enfance ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1457, 292, 'La diversité dans les écoles aide-t-elle tous les élèves à mieux s’épanouir ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1462, 293, 'Les universités devraient-elles bénéficier de plus de financements ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1467, 294, 'Quelles leçons ou matières devraient avoir plus de place dans les programmes scolaires ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1472, 295, 'À votre avis, faut-il de l’autorité pour élever correctement un enfant ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1477, 296, 'Faut-il avoir un niveau d’études élevé pour réussir dans la vie ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1482, 297, 'De jeunes Canadiens choisissent d’habiter chez leurs parents, parce qu’ils s’y sentent confortables. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1487, 298, 'Est-ce que l’école offre les mêmes chances à tous les élèves ? Partagez votre opinion .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1492, 299, 'Pensez-vous que les jeux vidéo peuvent participer à l’évolution d’un enfant ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1497, 300, 'La télévision est-elle un bon outil pour acquérir des connaissances ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1502, 301, 'À votre avis, quels enseignements l’école devrait-elle proposer afin de renforcer la motivation et l’intérêt des élèves ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1507, 302, 'Quelle matière appréciez-vous le plus à l’école ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1512, 303, 'Pensez-vous qu’il soit important que filles et garçons reçoivent la même éducation ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1517, 304, 'Doit-on apprendre les technologies à l’école dès le plus jeune âge ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1522, 305, 'Pensez-vous que l’autorité soit indispensable pour bien éduquer les enfants ? Justifiez votre point de vue .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1527, 306, 'Selon vous, est-il nécessaire de suivre de longues études pour réussir dans la vie ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1532, 307, 'L’éducation à l’environnement devrait commencer très tôt chez les enfants. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1537, 308, 'La plupart des gens essaient-ils de paraître plus jeunes que leur âge ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1542, 309, 'Les jeux vidéo constituent-ils un danger pour les joueurs ? Expliquez pourquoi .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1547, 310, 'Pensez-vous que les établissements scolaires devraient valoriser davantage les activités liées à l’art (musique, théâtre, arts visuels, etc.) ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1552, 311, 'À votre avis, peut-on vivre sans Internet ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1557, 312, 'Utiliser les réseaux sociaux est une perte de temps. Qu''en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1562, 313, 'Nous utilisons tous les jours des appareils électroniques (ordinateurs, téléphones portables, tablettes, etc.). Selon vous, quels sont les risques liés à leur utilisation ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1567, 314, 'Certains économistes pensent que les nouvelles technologies vont détruire les emplois. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1572, 315, 'Avec Internet, on vit mieux. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1577, 316, 'À votre avis, faut-il interdire l''usage du téléphone portable à l''école ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1582, 317, 'À votre avis, l''usage des téléphones portables devrait-il être interdit aux enfants ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1587, 318, 'On est mieux informé grâce à Internet. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1592, 319, 'Les téléphones portables facilitent la communication. Etes-vous d''accord avec cette affirmation? Pourquoi?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1597, 320, 'Internet nous rend heureux. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1602, 321, 'De nos jours, les gens ne s’envoient presque plus de courrier (cartes de vœux, lettres d’amour, etc. Est-ce regrettable ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1607, 322, 'Le téléphone portable est-il indispensable selon vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1612, 323, 'Le téléphone portable est un objet indispensable à la vie de tous les jours. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1617, 324, 'Il est facile de se passer de son téléphone portable. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1622, 325, 'Certaines personnes refusent de regarder les actualités diffusées à la télévision. Qu''en pensez-vous?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1627, 326, 'L''Internet rend les gens solitaires. Que pensez-vous de cette affirmation?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1632, 327, 'Certaines personnes préfèrent vivre sans technologie (Internet, ordinateur, téléphone). Qu’en pensez-vous?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1637, 328, 'Avec Internet le monde est devenu un village. Êtes-vous d’accord?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1642, 329, 'Les journaux télévisés ne devraient pas diffuser d’images violentes. Êtes-vous d’accord?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1647, 330, 'Êtes-vous d''accord avec l''idée que les journaux télévisés devraient éviter de diffuser des images violentes ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1652, 331, 'Les amitiés sur Internet ont-elles une base aussi solide que les amitiés familiales ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1657, 332, 'Les nouvelles technologies ont un impact positif sur notre société. Qu''en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1662, 333, 'De nos jours, beaucoup de personnes changent régulièrement de téléphone portable. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1667, 334, 'Discutez de l’impact des caméras de surveillance en milieu public sur la sécurité et la vie privée.', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1672, 335, 'Pensez-vous qu’Internet contribue réellement au bonheur des gens ? Justifiez votre réponse .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1677, 336, 'Grâce à Internet, sommes-nous mieux informés qu’avant ? Donnez votre avis .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1682, 337, 'Les relations d’amitié virtuelles sur Internet peuvent-elles être aussi solides que les liens familiaux ? Expliquez votre point de vue .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1687, 338, 'Pensez-vous que les réseaux sociaux sont une perte de temps ou, au contraire, un outil utile ? Justifiez votre point de vue .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1692, 339, 'Avec le développement d’Internet, les frontières semblent s’effacer, transformant le monde en un « village global ». Dans quelle mesure partagez-vous cette vision ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1697, 340, 'Les médias doivent-ils limiter la diffusion d’images violentes dans les journaux télévisés ? Quels sont les enjeux éthiques et informatifs liés à cette question ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1702, 341, 'L’utilisation quotidienne des appareils électroniques comporte certains risques. Quels sont, selon vous, les principaux dangers associés à leur usage ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1707, 342, 'Avec l’évolution des outils numériques, de nombreuses tâches du quotidien sont devenues plus rapides à réaliser. Partagez-vous cette opinion ? Donnez des exemples pour illustrer votre réponse.', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1712, 343, 'Pensez-vous qu''Internet améliore notre quotidien ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1717, 344, 'Quels sont, selon vous, les impacts et les éventuels dangers d’une utilisation quotidienne des appareils électroniques comme les téléphones, les ordinateurs et les tablettes ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1722, 345, 'On dit souvent qu''Internet a rendu le monde plus connecté, comme un petit village. Êtes-vous d''accord avec cette affirmation ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1727, 346, 'Internet rend-il la vie plus facile, selon vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1732, 347, 'Aujourd’hui, les échanges par lettres ou cartes sont devenus très rares. Est-ce une évolution regrettable selon vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1737, 348, 'Pensez-vous que les outils numériques nous aident à mieux gérer notre temps au quotidien ? Expliquez .', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1742, 349, 'Pensez-vous que, dans le futur, les nouvelles technologies pourront remplacer le travail humain ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1747, 350, 'Internet a-t-il un impact positif sur le bonheur des personnes ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1752, 351, 'Peut-on vraiment tout acheter sur Internet ? Qu’en dites-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1757, 352, 'Pensez-vous que l’utilisation des réseaux sociaux empêche de se concentrer sur l’essentiel ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1762, 353, 'Pensez-vous qu’Internet a vraiment rapproché les gens partout dans le monde ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1767, 354, 'Pensez-vous qu’il faut protéger le public, notamment les jeunes, des images violentes aux infos ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1772, 355, 'Les relations créées sur Internet sont-elles aussi fortes que les liens familiaux ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1777, 356, 'Croyez-vous que les enfants restent-ils trop longtemps devant les écrans (TV, téléphone, ordinateur, tablette) ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1782, 357, 'Pensez-vous qu’on puisse vivre aujourd’hui sans Internet ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1787, 358, 'Certaines préfèrent ne plus regarder les actualités télévisées. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1792, 359, 'L’utilisation d’Internet peut amener les personnes à se sentir seules ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1797, 360, 'Pensez-vous qu’on puisse encore se passer du téléphone portable ? Qu’en dites-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1802, 361, 'Les amitiés formées sur Internet sont-elles aussi solides que les liens familiaux ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1807, 362, 'L’utilisation des réseaux sociaux ou des applications rend-elle les gens moins dynamiques ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1812, 363, 'Aujourd’hui, les personnes n’échangent presque plus de lettres ou de cartes (de vœux, d’amour, etc.). Pensez-vous que c’est dommage ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1817, 364, 'Est-il important d’apprendre à utiliser les nouvelles technologies (Internet, réseaux sociaux, etc.) dès l’enfance ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1822, 365, 'La consommation d’objets comme les vêtements et les téléphones est-elle excessive ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1827, 366, 'À l’avenir, grâce aux nouvelles technologies, le travail ne sera plus nécessaire. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1832, 367, 'Quels impacts et quels risques peuvent avoir l’usage régulier des téléphones, des ordinateurs et des tablettes ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1837, 368, 'Les outils digitaux aident à économiser du temps dans la vie de tous les jours. Partagez-vous cet avis ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1842, 369, 'Grâce aux réseaux sociaux, il est plus facile de se faire des connaissances et des amitiés. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1847, 370, 'Il est difficile de vivre seul(e). Êtes-vous d''accord ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1852, 371, 'À la maison, les parents devraient interdire à leurs enfants l’utilisation d’Internet. Êtes-vous d’accord avec cette affirmation ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1857, 372, 'Les parents doivent contrôler les fréquentations de leurs enfants. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1862, 373, 'Avoir une grande famille ou de bons amis ? Qu''en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1867, 374, 'Les parents donnent de l''argent à leurs enfants pour avoir des bonnes notes. Que pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1872, 375, 'Les membres de notre famille sont nos meilleurs amis. Êtes-vous d’accord avec cette affirmation ? pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1877, 376, 'Est-ce bien de travailler avec des amis ou des membres de sa famille ? Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1882, 377, 'Les animaux de compagnie sont-ils essentiels pour le bien-être des personnes âgées ? Qu''en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1887, 378, 'La gentillesse permet toujours d''être entendu et respecté. Êtes-vous d''accord avec cette affirmation?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1892, 379, 'On peut vivre heureux en étant célibataire. Etes-vous d''accord?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1897, 380, 'Il est plus facile de vivre seul(e) qu’en famille. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1902, 381, 'Selon vous, est-il plus simple et agréable de vivre seul que de vivre en famille ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1907, 382, 'Pensez-vous qu’il soit plus simple de vivre seul(e) que de vivre en famille ?', '', 'fr');
