insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2502, 501, 'À votre avis, les activités culturelles comme les musées ou les théâtres devraient-elles être gratuites ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2507, 502, 'Voyager dans un pays étranger peut influencer la personnalité. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2512, 503, 'À votre avis, voyager a-t-il une réelle utilité ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2517, 504, 'Voyager seul(e) est-il parfois un meilleur choix que voyager accompagné(e) ? Quel est votre avis ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2522, 505, 'Préférez-vous aller au théâtre ou au cinéma ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2527, 506, 'La croissance du tourisme peut détériorer certaines régions. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2532, 507, 'Pensez-vous que le tourisme puisse favoriser le développement dans tous les pays ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2537, 508, 'Quelles expériences ou sites recommanderiez-vous à un étranger qui visite votre pays pour la première fois ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2542, 509, 'Selon vous, parmi les principaux enjeux actuels (humanitaire, social ou culturel), laquelle mérite d’être priorisée dans le monde actuel ? Justifiez .', '', 'fr');
