insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2552, 511, 'Croyez-vous que les personnes continuent à cuisiner régulièrement aujourd’hui ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2557, 512, 'De nombreuses personnes n’apprécient pas de voyager seuls. Partagez-vous cette opinion ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2562, 513, 'Pourquoi les gens s’intéressent-ils aux voyages en train, en avion ou en bus (selon le contexte local) ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2567, 514, 'Selon vous, les voyages sont-ils bénéfiques ? Pourquoi ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2572, 515, 'Pensez-vous qu’il serait préférable que les musées, théâtres et autres sites culturels soient ouverts gratuitement au public ? Pourquoi ?', '', 'fr');
