insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2582, 517, 'Pour des raisons d’égalité, certains gouvernements comptent 50% d’hommes et 50% de femmes. Qu’en pensez-vous ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2587, 518, 'Pendant leur temps libre, certaines personnes s’engagent dans des associations pour aider les autres. Qu’en pensez-vous ?', '', 'fr');
