insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2647, 530, 'Faut-il rendre les soins médicaux gratuits pour tout le monde ?', '', 'fr');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2652, 531, 'Pensez-vous que l’État a des limites dans son contrôle ? Pourquoi ?', '', 'fr');
