insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (96, 32, 'Welches Medium bevorzugen Sie, um sich zu informieren, und warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (99, 33, 'Ist es notwendig, Beziehungen zu Einheimischen aufzubauen, um sich in einem fremden Land wohlzufühlen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (102, 34, 'Sollte man mit Kindern im Ausland die Sprache des Gastlandes oder die Muttersprache sprechen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (105, 35, 'Ist es möglich, die Wirtschaft zu entwickeln und gleichzeitig die Umwelt zu schützen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (108, 36, 'Sollte man im Gastland seine Traditionen und Kultur bewahren?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (111, 37, 'Ist es eine gute Idee, Kindern Geld für gute Noten zu geben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (114, 38, 'Ist Wohlbefinden am Arbeitsplatz wirklich wichtig?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (117, 39, 'Verdienen Profisportler ihre hohen Gehälter?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (120, 40, 'Verschwindet das Fernsehen allmählich?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (123, 41, 'Verbringen Kinder zu viel Zeit vor Bildschirmen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (126, 42, 'Ist es leicht, im Ausland einen Job zu finden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (129, 43, 'Sollte man seine Gewohnheiten in einem Gastland ändern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (218, 44, 'Ist es Ihrer Meinung nach einfach, Freunde zu finden, wenn man in ein neues Land zieht? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (223, 45, 'Einwanderer sind eine Bereicherung für ein Land. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (228, 46, 'Um sich zu integrieren, müssen Sie die Sprache des Landes lernen, in dem Sie leben. Stimmen Sie zu? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (233, 47, 'Glauben Sie, dass es für junge Menschen einfacher ist, im Ausland zu leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (238, 48, 'Es ist möglich, in einem Land zu leben, ohne dessen Sprache zu sprechen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (243, 49, 'Die Entscheidung, Ihr Land zu verlassen, ist einfach. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (248, 50, 'Das Leben in einem fremden Land ist schwierig. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (253, 51, 'Einwanderung kommt den Aufnahmeländern zugute. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (258, 52, 'Ist ein Aufenthalt im Ausland ein Garant für beruflichen Erfolg?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (263, 53, 'Fällt es Ihnen leicht, mit Ihrer Herkunftskultur verbunden zu bleiben, wenn Sie in einem anderen Land leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (268, 54, 'Es ist einfacher, sich in einem neuen Land zu integrieren, wenn man Kinder hat. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (273, 55, 'Ist das Leben im Ausland Ihrer Meinung nach eine positive oder eine negative Erfahrung? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (278, 56, 'Wenn Sie in einem fremden Land leben, sollten Sie Kontakte zu Menschen aus Ihrem Heimatland knüpfen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (283, 57, 'Es ist einfach, sich in jungen Jahren in einem fremden Land zu integrieren. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (288, 58, 'Eine Erfahrung im Ausland ist immer positiv. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (293, 59, 'Ist Ihrer Meinung nach jeder in der Lage, sich an das Leben in einem fremden Land anzupassen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (298, 60, 'Wie kann eine Regierung aus Ihrer Sicht die Integration von Ausländern erleichtern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (303, 61, 'Halten Sie eine Welt ohne Grenzen, Pässe und Visa für möglich? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (308, 62, 'Ist eine Welt ohne Grenzen, Pässe und Visa möglich? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (313, 63, 'Um sich gut zu integrieren, muss man seine Traditionen aufgeben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (318, 64, 'Müssen Sie Ihre Traditionen aufgeben, um sich in einem neuen Land gut zu integrieren? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (323, 65, 'Was sind Ihrer Meinung nach die drei wichtigsten Fragen, die Sie sich stellen sollten, bevor Sie mit dem Einwanderungsprozess nach Quebec beginnen? Warum diese drei?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (328, 66, 'Was sind die Hauptmotive, die Menschen dazu veranlassen, in andere Länder auszuwandern? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (333, 67, 'Für die Integration in ein Aufnahmeland gibt es keine Altersgrenze. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (338, 68, 'Wenn Sie ins Ausland reisen, ist es wichtig, Englisch sprechen zu können. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (343, 69, 'Muss man Ihrer Meinung nach die Sprache eines Landes beherrschen, bevor man dorthin einwandert? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (348, 70, 'Allein oder mit der Familie auswandern – was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (353, 71, 'Ist es besser, alleine oder mit der Familie auszuwandern? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (358, 72, 'Wenn Sie im Ausland leben, ist es wichtig, in der Gemeinschaft Ihres Heimatlandes zu bleiben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (363, 73, 'Anpassung im Ausland: Sprechen Sie über die Vorteile und Herausforderungen der Integration junger Menschen, wenn sie ins Ausland ziehen.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (368, 74, 'Sollten Sie Ihre Traditionen aufgeben, um sich gut in ein neues Land zu integrieren? Geben Sie Ihre Meinung ab.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (373, 75, 'Ist die Integration in einem fremden Land für junge Menschen einfacher als für Erwachsene? Erläutern Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (378, 76, 'Ist das Leben im Ausland eine positive oder eine negative Erfahrung? Geben Sie Ihre Meinung ab und erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (383, 77, 'Bietet Einwanderung einen Mehrwert für die Aufnahmeländer? Teilen Sie Ihre Meinung mit und unterstützen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (388, 78, 'Ist das Erlernen der Sprache des Landes, in dem Sie leben, für eine bessere Integration notwendig? Teilen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (393, 79, 'Muss man Ihrer Meinung nach in einem Land leben, um dessen Kultur zu verstehen? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (398, 80, 'Ist es wichtig, in einem Land zu leben, um seine Kultur zu verstehen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (403, 81, 'Muss man in einem Land leben, um dessen Kultur vollständig zu verstehen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (408, 82, 'Muss man in einem Land leben, um seine Kultur wirklich zu verstehen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (413, 83, 'Das Leben im Ausland ist für viele Menschen eine echte Herausforderung. Sind Sie einverstanden? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (418, 84, 'Glauben Sie, dass Einwanderer einen positiven Beitrag zum Wohlstand eines Landes leisten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (423, 85, 'Ist das Leben im Ausland eine Herausforderung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (428, 86, 'Glauben Sie, dass jeder in der Lage ist, sich im Ausland zu integrieren und anzupassen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (433, 87, 'Glauben Sie, dass ein Aufenthalt im Ausland ein Garant für beruflichen Erfolg ist? Warum oder warum nicht?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (438, 88, 'Ist ein Umzug ins Ausland ein Garant für beruflichen Erfolg? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (443, 89, 'Sind Sie der Meinung, dass ein Leben im Ausland immer von Vorteil ist?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (448, 90, 'Können Sie leicht Freunde finden, wenn Sie in einem neuen Land ankommen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (453, 91, 'Denken Sie, dass es für eine gute Integration wichtig ist, die Sprache des Landes, in dem Sie leben, fließend zu beherrschen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (458, 92, 'Glauben Sie, dass die Integration in ein neues Land für junge Menschen einfacher ist?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (463, 93, 'Wann ist der beste Zeitpunkt für eine Auswanderung? Geben Sie Ihre Meinung ab.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (468, 94, 'Das Verlassen des Landes, um sich im Ausland niederzulassen, ist oft eine erzwungene Entscheidung. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (473, 95, 'Die Eingewöhnung in einem neuen Land ist oft schwierig. Sind Sie einverstanden? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (478, 96, 'Spielen Einwanderer Ihrer Meinung nach eine nützliche Rolle für die Entwicklung eines Landes?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (483, 97, 'Müssen Unternehmen neue Mitarbeiter bei der Anpassung und Integration unterstützen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (488, 98, 'Was ist Ihrer Meinung nach das beste Alter, um im Ausland zu leben? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (493, 99, 'Ist es einfacher, mit seinen Lieben ins Ausland zu ziehen, als alleine zu gehen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (498, 100, 'Wenn Sie in einem neuen Land leben, müssen Sie Ihren Lebensstil anpassen (Kleidung, Essen, Urlaub usw.)?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (503, 101, 'Überwiegen die Vorteile eines Lebens im Ausland die Nachteile? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (508, 102, 'Ein Umzug ins Ausland erfordert viel Mut. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (513, 103, 'Welche Gründe könnten Ihrer Meinung nach dazu führen, dass jemand im Ausland arbeitet?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (518, 104, 'Reicht es für eine erfolgreiche Integration aus, die Sprache des Gastlandes zu beherrschen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (523, 105, 'Was sind die drei wichtigsten Dinge, über die Sie nachdenken sollten, bevor Sie ein Einwanderungsprojekt nach Quebec starten? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (528, 106, 'Glauben Sie, dass das Leben im Ausland ein Garant für den beruflichen Erfolg ist? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (533, 107, 'Ist es Ihrer Meinung nach wichtig, Fremdsprachen zu lernen? Aus welchen Gründen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (538, 108, 'Ein Aufenthalt im Ausland bringt immer Vorteile. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (543, 109, 'Müssen Sie die Sprache des Landes sprechen, in dem Sie leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (548, 110, 'Ist es einfacher, sich in jungen Jahren an ein neues Land anzupassen? Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (553, 111, 'Lässt Sie das langjährige Auslandsleben Ihrer Meinung nach Ihre Herkunftskultur vergessen? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (558, 112, 'Welche Maßnahmen kann ein Land Ihrer Meinung nach ergreifen, um Ausländern die Integration zu erleichtern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (563, 113, 'Denken Sie, dass es einfach ist, die Kultur Ihrer Herkunft zu bewahren, während Sie im Ausland leben? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (568, 114, 'Können Kinder Ihnen Ihrer Meinung nach dabei helfen, sich besser zu integrieren, wenn Sie in einem fremden Land ankommen? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (573, 115, 'Ist es Ihrer Meinung nach einfach, Freundschaften zu schließen, wenn man in einem fremden Land ankommt? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (578, 116, 'Um Ihren Job gut zu machen, ist es wichtig, dass Sie ihn mögen. Sind Sie einverstanden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (583, 117, 'Braucht es Ihrer Meinung nach Spaß am Beruf, um beruflich erfolgreich zu sein? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (588, 118, 'Ist Freude am Beruf ein wesentliches Kriterium für den beruflichen Erfolg? Begründen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (593, 119, 'In Zukunft werden wir mit neuen Technologien nicht mehr arbeiten müssen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (598, 120, 'Im Ausland zu arbeiten ist einfach. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (603, 121, 'Glauben Sie, dass es einfach ist, im Ausland zu arbeiten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (608, 122, 'Ist es sinnvoll, im Laufe der Karriere mehrere verschiedene Jobs zu haben? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (613, 123, 'Muss man seinen Job mögen, um produktiv zu sein? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (618, 124, 'Hilft es Ihnen, produktiver zu sein, wenn Sie Ihren Job mögen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (623, 125, 'Gleichzeitiges Arbeiten und Studieren ist schwierig. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (628, 126, 'Ein Berufswechsel ist heutzutage in jedem Alter möglich. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (633, 127, 'Unternehmen sollten neue Mitarbeiter dabei unterstützen, sich gut zu integrieren. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (638, 128, 'Das Gehalt ist der wichtigste Aspekt eines Jobs. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (643, 129, 'In einem Unternehmen sollen alle das gleiche Gehalt verdienen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (648, 130, 'Der berufliche Erfolg hängt von Ihrem Bildungsniveau und dem erworbenen Abschluss ab. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (653, 131, 'Ein Studium hilft Ihnen, beruflich erfolgreich zu sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (658, 132, 'Eine höhere Bildung hilft Ihnen, in Ihrer Karriere erfolgreich zu sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (663, 133, 'Ist Ihrer Meinung nach das Gehalt der wichtigste Faktor, der Mitarbeiter motiviert? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (668, 134, 'Manche Leute meinen, man sollte es vermeiden, mit einem Familienmitglied zusammenzuarbeiten. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (673, 135, 'Manche Leute denken, man sollte nicht mit Freunden oder der Familie zusammenarbeiten. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (678, 136, 'Glauben Sie, dass Sie dort leicht einen Job finden werden, wenn Sie nach Kanada ziehen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (683, 137, 'Arbeiten bis 70 – was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (688, 138, 'Was halten Sie von der Idee, bis zum 70. Lebensjahr zu arbeiten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (693, 139, 'Halten Sie es für eine gute Idee, bis zum 70. Lebensjahr zu arbeiten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (698, 140, 'Arbeiten Sie lieber unter der Aufsicht eines Mannes oder einer Frau? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (703, 141, 'Halten Sie es für eine akzeptable Maßnahme, Menschen bis zum Alter von 70 Jahren arbeiten zu lassen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (708, 142, 'Das Wichtigste in einem Job ist das Gehalt. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (713, 143, 'Die härtesten Jobs sollten die bestbezahlten Jobs sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (718, 144, 'Was halten Sie von Remote-Arbeit?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (723, 145, 'Um gut funktionieren zu können, sollte ein Unternehmen dem Wohlbefinden seiner Mitarbeiter Priorität einräumen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (728, 146, 'In jungen Jahren ist es schwieriger, einen Job zu finden. Sind Sie einverstanden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (733, 147, 'Berufs- oder Hochschulerfahrung im Ausland ist Voraussetzung für den beruflichen Erfolg. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (738, 148, 'Welchen Sinn hat eine Berufs- oder Studienerfahrung im Ausland?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (743, 149, 'Sollten Arbeitgeber Nickerchen am Arbeitsplatz erlauben? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (748, 150, 'Jeder ist in der Lage, Manager oder Leiter zu sein (Abteilungs-, Geschäfts-, Vereinsleiter etc.). Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (753, 151, 'Um beruflich erfolgreich zu sein, muss man gut aussehen. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (758, 152, 'Diplome sind für den beruflichen Erfolg unerlässlich. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (763, 153, 'Um auf der Karriereleiter aufzusteigen, müssen Sie in Ihrem Job kompetent sein. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (768, 154, 'Sollten Arbeitgeber ihren Mitarbeitern erlauben, sich während ihres gesamten Berufslebens weiterzubilden? Ist es für alle von Vorteil?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (773, 155, 'Die Zunahme der Fernarbeit ist ein Fortschritt für alle. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (778, 156, 'Fernarbeit: Analysieren Sie die Vorteile und Herausforderungen der Fernarbeit, insbesondere im Hinblick auf das Zeitmanagement.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (783, 157, 'Wahl der Kleidung: Besprechen Sie, wie wichtig Kleidung im beruflichen Kontext ist, insbesondere bei der Fernarbeit.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (788, 158, 'Glauben Sie, dass ein Unternehmen das Wohlergehen der Mitarbeiter priorisieren sollte, um sicherzustellen, dass es gut läuft? Begründen Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (793, 159, 'Heutzutage wird ein Studium oft als unabdingbar angesehen, um einen Job zu finden. Teilen Sie Ihre Meinung zu dieser Aussage mit.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (798, 160, 'Sollen wir bis zum 70. Lebensjahr arbeiten? Geben Sie Ihre Meinung zu dieser Frage ab.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (803, 161, 'Ist das Gehalt der wichtigste Faktor, der Mitarbeiter in einem Unternehmen motiviert? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (808, 162, 'Garantiert ein Studium beruflichen Erfolg? Erläutern Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (813, 163, 'Ist Auslandserfahrung ein wesentlicher Vorteil für den beruflichen Erfolg? Begründen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (818, 164, 'Könnte Technologie in naher Zukunft die menschliche Arbeit vollständig ersetzen? Geben Sie Ihre Meinung ab.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (823, 165, 'Ist ein Berufswechsel wirklich zu jedem Zeitpunkt im Leben möglich? Welche Herausforderungen und Chancen bringt eine berufliche Veränderung mit sich?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (828, 166, 'Arbeiten Sie lieber unter der Führung eines Mannes oder unter der einer Frau? Erläutern Sie Ihren Standpunkt und begründen Sie Ihre Wahl.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (833, 167, 'Glauben Sie, dass Ihnen ein Umzug in ein anderes Land mehr berufliche und persönliche Möglichkeiten bietet? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (838, 168, 'Welche Vorteile hat es, schon in jungen Jahren eine Fremdsprache zu lernen? Fördert es die Integration und den beruflichen Aufstieg als Erwachsener?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (843, 169, 'Lohnt es sich, im Laufe der Karriere mehrmals den Arbeitsplatz zu wechseln?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (848, 170, 'Trägt Ihnen die Freude an Ihrem Job zum Erfolg bei? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (853, 171, 'Sollen neue Mitarbeiter gefördert werden, damit sie sich leichter integrieren können? Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (858, 172, 'Glauben Sie, dass ein Berufswechsel in jedem Alter möglich ist? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (863, 173, 'Halten Sie es für sinnvoll, im Laufe Ihres Berufslebens mehrere verschiedene Jobs auszuüben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (868, 174, 'Finden Sie es akzeptabel, das Renteneintrittsalter auf 70 Jahre anzuheben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (873, 175, 'Sollten junge Menschen Ihrer Meinung nach arbeiten, um ihr Studium zu finanzieren?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (878, 176, 'Glauben Sie, dass ein guter Abschluss Ihnen wirklich dabei hilft, beruflich erfolgreich zu sein? Erläutern Sie Ihre Ansicht.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (883, 177, 'Ist das Gehalt der wichtigste Faktor in einem Job? Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (888, 178, 'In jungen Jahren kann es schwieriger sein, einen Job zu finden. Sind Sie einverstanden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (893, 179, 'Glauben Sie, dass Sie besser arbeiten, wenn Ihnen gefällt, was Sie tun?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (898, 180, 'Kann man Ihrer Meinung nach auch im fortgeschrittenen Alter einen neuen Beruf starten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (903, 181, 'Ist Auslandserfahrung für den beruflichen Erfolg notwendig? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (908, 182, 'Wie können Unternehmen die Integration neuer Mitarbeiter erleichtern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (913, 183, 'Kann das Leben in verschiedenen Ländern Ihre Karriereaussichten verbessern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (918, 184, 'Ist es wichtig, dass Sie Ihren Job mögen, um beruflich erfolgreich zu sein? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (923, 185, 'Der wichtigste Faktor für den beruflichen Erfolg in einem Unternehmen ist die Beherrschung Ihres Jobs. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (928, 186, 'Wäre es leicht, einen Job zu finden, wenn Sie nach Kanada ziehen würden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (933, 187, 'Glauben Sie, dass ein Aufenthalt im Ausland Ihnen beruflich zum Erfolg verhilft?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (938, 188, 'Glauben Sie, dass Sie Ihren Job meistern müssen, um innerhalb eines Unternehmens aufzusteigen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (943, 189, 'Sollten Arbeitgeber während der gesamten beruflichen Laufbahn der Mitarbeiter Schulungen anbieten? Ist es für alle von Vorteil?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (948, 190, 'Sind Mitarbeiter hauptsächlich durch das Gehalt motiviert? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (953, 191, 'Glauben Sie, dass das Leben in mehreren Ländern Ihre Karrierechancen verbessern kann?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (958, 192, 'Welchen Beruf würden Sie gerne eines Tages ausprobieren? Begründen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (963, 193, 'Halten Sie es für wichtig, dass jeder von zu Hause aus arbeiten kann, wenn er möchte?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (968, 194, 'Glauben Sie, dass es notwendig ist, Spaß am Beruf zu haben, um beruflich erfolgreich zu sein? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (973, 195, 'Haben Unternehmen die Verantwortung, neue Mitarbeiter zu unterstützen, damit diese sich leichter integrieren können? Teilen Sie diese Idee?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (978, 196, 'Glauben Sie, dass Remote-Arbeit wirklich zu einer besseren Work-Life-Balance beiträgt?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (983, 197, 'Vertrauen Sie den Informationen, die Sie im Internet lesen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (988, 198, 'Erfordert beruflicher Erfolg eine Auslandserfahrung? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (993, 199, 'Es ist eine gute Sache, den Mitarbeitern zu erlauben, bei der Arbeit ein Nickerchen zu machen. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (998, 200, 'Ist es sinnvoll, Menschen bis zum Alter von 70 Jahren arbeiten zu lassen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1003, 201, 'Sollten Unternehmen die Fernarbeit ihrer Mitarbeiter reduzieren? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1008, 202, 'Mit dem Internet erhalten wir mehr Informationen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1013, 203, 'Sollten junge Menschen Ihrer Meinung nach arbeiten, um die Kosten für ihr Studium zu finanzieren? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1018, 204, 'Ist es das Wichtigste im Leben, bei der Arbeit glücklich zu sein? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1023, 205, 'Ist es einfach, in einem anderen Land zu arbeiten? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1028, 206, 'Heutzutage ist oft ein Diplom notwendig, um einen Job zu bekommen. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1033, 207, 'Benötigen Sie Diplome, um in Ihrer Karriere erfolgreich zu sein? Begründen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1038, 208, 'Sollten Arbeitgeber den Arbeitnehmern erlauben, sich am Arbeitsplatz auszuruhen? Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1043, 209, 'Glauben Sie, dass jeder eine Führungsrolle übernehmen kann – zum Beispiel in einer Abteilung, einem Geschäft oder einem Verein? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1048, 210, 'Jeden Sommer veröffentlichen Zeitschriften Tipps zum Abnehmen. Sind diese Empfehlungen Ihrer Meinung nach effektiv und glaubwürdig? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1053, 211, 'Heutzutage werden junge Menschen immer unhöflicher. Sind Sie einverstanden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1058, 212, 'Gute Noten in der Schule helfen, im Leben erfolgreich zu sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1063, 213, 'Gute Schulnoten sind ein Schlüsselfaktor für den Erfolg im Leben. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1068, 214, 'Es ist normal, dass junge Menschen arbeiten, um ihr Studium zu finanzieren. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1073, 215, 'Glauben Sie, dass Autorität bei der Erziehung eines Kindes notwendig ist? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1078, 216, 'Sollten Eltern streng mit ihren Kindern sein? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1083, 217, 'Manche Eltern nehmen ihr Kind aus der Schule und unterrichten es zu Hause. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1088, 218, 'Welche Fächer sollten in der Schule unterrichtet werden, um die Schüler mehr zu interessieren? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1093, 219, 'Was war dein Lieblingsfach in der Schule? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1098, 220, 'Manche Eltern geben ihren Kindern Geld, wenn sie in der Schule gut abschneiden. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1103, 221, 'Fernsehen trägt zur Entwicklung eines Kindes bei. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1108, 222, 'Kinder integrieren sich leicht in einem fremden Land. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1113, 223, 'Sie sollten Kindern immer die Wahrheit sagen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1118, 224, 'Die Lehrpläne der Schulen sollten künstlerischen Aktivitäten (Musik, Theater, Zeichnen usw.) mehr Raum geben.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1123, 225, 'Eine Fremdsprache zu lernen ist schwierig. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1128, 226, 'Ist es schwierig, eine Fremdsprache zu lernen? Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1133, 227, 'Brauchen Universitäten Ihrer Meinung nach mehr Geld? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1138, 228, 'Zeit, die man vor dem Fernseher verbringt, ist verschwendete Zeit. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1143, 229, 'Manche Menschen entscheiden sich dafür, nie fernzusehen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1148, 230, 'Fernsehen kann lehrreich sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1153, 231, 'Sind Diplome wichtiger als Erfahrung? (Brauchen Sie Erfahrung, um einen Job zu bekommen?)', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1158, 232, 'Für die Jobsuche ist Erfahrung wichtiger als Diplome. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1163, 233, 'Sollten wir unsere Kinder das Internet nutzen lassen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1168, 234, 'Videospiele tragen zur Entwicklung eines Kindes bei. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1173, 235, 'Es ist nie zu spät zum Lernen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1178, 236, 'Fernsehen trägt zur Entwicklung von Kindern bei. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1183, 237, 'Kann man heutzutage ohne Fernsehen leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1188, 238, 'Ist es heutzutage möglich, ohne Fernsehen zu leben? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1193, 239, 'Manche Eltern geben ihren Kindern Geld für gute Noten. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1198, 240, 'Manche Menschen entscheiden sich dafür, die Nachrichten nicht im Fernsehen zu verfolgen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1203, 241, 'Das Internet verbessert die Bildung junger Menschen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1208, 242, 'Videospiele sind für junge Menschen gefährlich. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1213, 243, 'Kinder sollten zum Sport gezwungen werden. Sind Sie einverstanden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1218, 244, 'Sollten wir Kinder zum Sport zwingen? Was denken Sie? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1223, 245, 'Kinder und Jugendliche sollten heute ein eigenes Mobiltelefon haben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1228, 246, 'Manche Menschen entscheiden sich dafür, keine Kinder zu haben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1233, 247, 'Das Internet hat einen positiven Einfluss auf die Bildung von Kindern. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1238, 248, 'Videospiele sind gefährlich. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1243, 249, 'Lernen junge Menschen leicht eine neue Sprache? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1248, 250, 'Videospiele sind gut für die Entwicklung von Kindern. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1253, 251, 'Können Videospiele die Entwicklung von Kindern unterstützen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1258, 252, 'Glauben Sie, dass Videospiele zur Entwicklung von Kindern beitragen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1263, 253, 'Können Videospiele Ihrer Meinung nach Kindern schaden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1268, 254, 'Welche Rolle spielt das Fernsehen Ihrer Meinung nach in der Bildung von Kindern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1273, 255, 'Glauben Sie, dass Autorität in der Kindererziehung eine wesentliche Rolle spielt?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1278, 256, 'Glauben Sie, dass das Internet eine positive Rolle bei der Bildung von Kindern spielt?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1283, 257, 'Sind Bildungsausflüge (Museen, Zoos, Galerien) für Kinder von Vorteil? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1288, 258, 'Trägt Vielfalt in den Schulen dazu bei, dass alle Schüler erfolgreich sind? Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1293, 259, 'Kinder sollten zur Teilnahme an sportlichen Wettkämpfen ermutigt werden. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1298, 260, 'Manche Eltern belohnen ihre Kinder mit Geld für gute Noten. Glauben Sie, dass dies eine gute pädagogische Methode ist? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1303, 261, 'Sollten Ökologie-/Umweltthemen schon in jungen Jahren in der Schule unterrichtet werden? Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1308, 262, 'Brauchen Universitäten mehr Mittel, um besser funktionieren zu können? Erläutern Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1313, 263, 'Ist das Erlernen einer Fremdsprache eine schwierige Herausforderung? Teilen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1318, 264, 'Lernen junge Menschen leichter neue Sprachen als Erwachsene? Begründen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1323, 265, 'Sind gute Noten wichtig, um im Leben erfolgreich zu sein? Teilen Sie Ihren Standpunkt und untermauern Sie ihn mit Argumenten.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1328, 266, 'Sollten Kinder und Jugendliche heutzutage ein eigenes Mobiltelefon haben? Was sind die Vor- und Nachteile?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1333, 267, 'Manche Menschen entscheiden sich dafür, keine Kinder zu haben. Welche Faktoren begründen diese Entscheidung und welche persönlichen und gesellschaftlichen Auswirkungen hat sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1338, 268, 'Glauben Sie, dass Videospiele eine positive Rolle bei der Entwicklung von Kindern spielen können? Begründen Sie Ihre Antwort unter Berücksichtigung pädagogischer und sozialer Aspekte.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1343, 269, 'Ist es sinnvoll, Kindern ein Mobiltelefon zu schenken?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1348, 270, 'Heutzutage lehnen junge Menschen den Gedanken an das Älterwerden ab. Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1353, 271, 'Denken Sie, dass es notwendig ist, lange zu studieren, um einen guten Lebensunterhalt zu verdienen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1358, 272, 'Glauben Sie, dass es beim Lernen keine Altersgrenze gibt?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1363, 273, 'Glauben Sie, dass Erwachsene junge Menschen negativ sehen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1368, 274, 'Welche Fächer sollten in der Schule hinzugefügt werden, um das Interesse der Schüler zu wecken? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1373, 275, 'Welches Fach hat dir in der Schule am besten gefallen? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1378, 276, 'Finden Sie es heutzutage wichtig, dass Kinder und Jugendliche ein eigenes Mobiltelefon haben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1383, 277, 'Sollte es Kindern verwehrt werden, ein Telefon zu benutzen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1388, 278, 'Die Hauptaufgabe der Schule besteht darin, akademische Fächer zu unterrichten. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1393, 279, 'Glauben Sie, dass schulische Leistungen einen Einfluss auf den Erfolg im Leben haben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1398, 280, 'Brauchen Teenager Ihrer Meinung nach wirklich ein eigenes Telefon?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1403, 281, 'Halten Sie es für akzeptabel, keine Kinder haben zu wollen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1408, 282, 'Können junge Menschen leicht eine Fremdsprache lernen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1413, 283, 'Gelingt es Ihrer Meinung nach jungen Menschen, eine Fremdsprache problemlos zu beherrschen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1418, 284, 'Welche Fächer sollten Schulen anbieten, um den Unterricht für die Schüler interessanter zu gestalten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1423, 285, 'Welchen Unterricht hast du in der Schule bevorzugt und warum hat er dir gefallen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1428, 286, 'Was war Ihr Lieblingsfach in der Schule und warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1433, 287, 'Welche Fächer sollten Ihrer Meinung nach mehr in der Schule unterrichtet werden und warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1438, 288, 'Fördert soziale und kulturelle Vielfalt in der Schule die Toleranz unter den Schülern? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1443, 289, 'Ist es für Organisationen notwendig, ihren Mitarbeitern regelmäßige Lernmöglichkeiten anzubieten? Ist dieser Zugang für den Einzelnen von Vorteil?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1448, 290, 'Was halten Sie von Menschen, die sich dazu entschließen, nie fernzusehen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1453, 291, 'Ist es besser, von Kindesbeinen an eine Fremdsprache zu lernen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1458, 292, 'Trägt Vielfalt in den Schulen dazu bei, dass alle Schüler erfolgreich sind?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1463, 293, 'Sollten Universitäten mehr Mittel erhalten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1468, 294, 'Welche Unterrichtsstunden oder Fächer sollten mehr Platz im Lehrplan haben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1473, 295, 'Braucht man Ihrer Meinung nach Autorität, um ein Kind richtig zu erziehen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1478, 296, 'Braucht man ein hohes Bildungsniveau, um im Leben erfolgreich zu sein? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1483, 297, 'Einige junge Kanadier entscheiden sich dafür, bei ihren Eltern zu leben, weil sie sich dort wohl fühlen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1488, 298, 'Bietet die Schule allen Schülern die gleichen Möglichkeiten? Teilen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1493, 299, 'Glauben Sie, dass Videospiele eine Rolle bei der Entwicklung eines Kindes spielen können?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1498, 300, 'Ist Fernsehen ein gutes Hilfsmittel zum Lernen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1503, 301, 'Was sollten Schulen Ihrer Meinung nach lehren, um die Motivation und das Interesse der Schüler zu stärken? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1508, 302, 'Welches Fach gefällt dir in der Schule am besten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1513, 303, 'Halten Sie es für wichtig, dass Mädchen und Jungen die gleiche Bildung erhalten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1518, 304, 'Sollte Technik schon in jungen Jahren in der Schule gelehrt werden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1523, 305, 'Glauben Sie, dass Autorität für eine gute Kindererziehung unerlässlich ist? Begründen Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1528, 306, 'Ist es Ihrer Meinung nach notwendig, lange zu lernen, um im Leben erfolgreich zu sein?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1533, 307, 'Umwelterziehung sollte für Kinder schon sehr früh beginnen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1538, 308, 'Versuchen die meisten Menschen, jünger auszusehen als sie sind? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1543, 309, 'Sind Videospiele eine Gefahr für Spieler? Erklären Sie, warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1548, 310, 'Glauben Sie, dass Schulen mehr Wert auf künstlerische Aktivitäten (Musik, Theater, bildende Kunst usw.) legen sollten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1553, 311, 'Können wir Ihrer Meinung nach ohne Internet leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1558, 312, 'Die Nutzung sozialer Medien ist Zeitverschwendung. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1563, 313, 'Wir nutzen täglich elektronische Geräte (Computer, Smartphones, Tablets usw.). Welche Risiken sind aus Ihrer Sicht mit der Verwendung verbunden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1568, 314, 'Einige Ökonomen glauben, dass neue Technologien Arbeitsplätze zerstören werden. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1573, 315, 'Mit dem Internet leben wir besser. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1578, 316, 'Sollten Ihrer Meinung nach Mobiltelefone in der Schule verboten werden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1583, 317, 'Sollte Ihrer Meinung nach Kindern die Nutzung von Mobiltelefonen verboten werden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1588, 318, 'Dank des Internets sind wir besser informiert. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1593, 319, 'Mobiltelefone erleichtern die Kommunikation. Sind Sie einverstanden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1598, 320, 'Das Internet macht uns glücklich. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1603, 321, 'Heutzutage verschickt man kaum noch Post (Grußkarten, Liebesbriefe etc.). Ist das etwas zu bereuen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1608, 322, 'Ist ein Mobiltelefon Ihrer Meinung nach unverzichtbar?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1613, 323, 'Ein Mobiltelefon ist im Alltag unverzichtbar. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1618, 324, 'Auf Ihr Mobiltelefon können Sie ganz einfach verzichten. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1623, 325, 'Manche Menschen weigern sich, die Nachrichten im Fernsehen zu sehen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1628, 326, 'Das Internet macht Menschen einsam. Was halten Sie von dieser Aussage?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1633, 327, 'Manche Menschen leben lieber ohne Technologie (Internet, Computer, Telefon). Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1638, 328, 'Mit dem Internet ist die Welt zu einem Dorf geworden. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1643, 329, 'Fernsehnachrichten sollten keine gewalttätigen Bilder senden. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1648, 330, 'Sind Sie der Meinung, dass Fernsehnachrichten die Darstellung gewalttätiger Bilder vermeiden sollten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1653, 331, 'Sind online geschlossene Freundschaften genauso stark wie familiäre Bindungen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1658, 332, 'Neue Technologien haben einen positiven Einfluss auf unsere Gesellschaft. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1663, 333, 'Heutzutage wechseln viele Menschen regelmäßig ihr Mobiltelefon. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1668, 334, 'Besprechen Sie, wie sich Überwachungskameras an öffentlichen Orten auf Sicherheit und Privatsphäre auswirken.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1673, 335, 'Glauben Sie, dass das Internet wirklich zum Glück der Menschen beiträgt? Begründen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1678, 336, 'Sind wir dank des Internets besser informiert als früher? Teilen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1683, 337, 'Können virtuelle Freundschaften im Internet genauso stark sein wie familiäre Bindungen? Erläutern Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1688, 338, 'Denken Sie, dass soziale Medien Zeitverschwendung oder im Gegenteil ein nützliches Werkzeug sind? Begründen Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1693, 339, 'Mit der Entwicklung des Internets scheinen die Grenzen zu verschwinden und die Welt in ein „globales Dorf“ zu verwandeln. Inwieweit stimmen Sie dieser Ansicht zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1698, 340, 'Sollten die Medien die Ausstrahlung gewalttätiger Bilder in den Nachrichten einschränken? Welche ethischen und informationellen Fragen stehen auf dem Spiel?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1703, 341, 'Der tägliche Umgang mit elektronischen Geräten birgt gewisse Risiken. Was sind Ihrer Meinung nach die größten Gefahren, die mit ihrer Verwendung verbunden sind?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1708, 342, 'Mit digitalen Tools lassen sich viele Alltagsaufgaben schneller erledigen. Sind Sie einverstanden? Nennen Sie Beispiele, um Ihre Antwort zu untermauern.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1713, 343, 'Glauben Sie, dass das Internet unser tägliches Leben verbessert?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1718, 344, 'Was sind Ihrer Meinung nach die Auswirkungen und möglichen Gefahren des täglichen Gebrauchs elektronischer Geräte wie Telefone, Computer und Tablets?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1723, 345, 'Die Leute sagen oft, dass das Internet die Welt vernetzter gemacht hat, wie ein kleines Dorf. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1728, 346, 'Macht das Internet Ihrer Meinung nach das Leben einfacher?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1733, 347, 'Heutzutage ist der Austausch von Briefen oder Karten sehr selten geworden. Halten Sie das für eine bedauerliche Änderung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1738, 348, 'Glauben Sie, dass uns digitale Tools dabei helfen, unsere Zeit im Alltag besser zu verwalten? Erklären.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1743, 349, 'Glauben Sie, dass neue Technologien in Zukunft menschliche Arbeit ersetzen könnten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1748, 350, 'Hat das Internet einen positiven Einfluss auf das Glück der Menschen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1753, 351, 'Kann man wirklich alles online kaufen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1758, 352, 'Denken Sie, dass die Nutzung sozialer Medien es schwieriger macht, sich auf das Wesentliche zu konzentrieren? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1763, 353, 'Glauben Sie, dass das Internet die Menschen auf der ganzen Welt wirklich einander näher gebracht hat?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1768, 354, 'Denken Sie, wir sollten die Öffentlichkeit – insbesondere junge Menschen – vor gewalttätigen Bildern in den Nachrichten schützen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1773, 355, 'Sind Beziehungen im Internet so stark wie familiäre Bindungen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1778, 356, 'Glauben Sie, dass Kinder zu viel Zeit vor Bildschirmen (Fernseher, Telefon, Computer, Tablet) verbringen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1783, 357, 'Glauben Sie, dass wir heute ohne Internet leben können? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1788, 358, 'Manche Menschen schauen sich die Nachrichten lieber nicht mehr im Fernsehen an. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1793, 359, 'Kann die Nutzung des Internets dazu führen, dass sich Menschen einsam fühlen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1798, 360, 'Glauben Sie, dass wir noch ohne Mobiltelefon auskommen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1803, 361, 'Sind Online-Freundschaften genauso stark wie familiäre Bindungen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1808, 362, 'Machen soziale Medien oder Apps die Menschen weniger aktiv und dynamisch? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1813, 363, 'Heutzutage werden kaum noch Briefe oder Karten (Grußkarten, Liebesbriefe etc.) ausgetauscht. Findest du das schade?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1818, 364, 'Ist es wichtig, den Umgang mit neuen Technologien (Internet, soziale Medien usw.) von Kindesbeinen an zu erlernen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1823, 365, 'Ist unser Konsum von Dingen wie Kleidung und Telefonen übermäßig? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1828, 366, 'Künftig werden dank neuer Technologien keine Arbeiten mehr nötig sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1833, 367, 'Welche Auswirkungen und Risiken kann die regelmäßige Nutzung von Telefonen, Computern und Tablets haben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1838, 368, 'Digitale Tools helfen, im Alltag Zeit zu sparen. Sind Sie einverstanden?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1843, 369, 'Dank der sozialen Medien ist es einfacher, Leute zu treffen und Freundschaften zu schließen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1848, 370, 'Allein zu leben ist schwierig. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1853, 371, 'Zu Hause sollten Eltern ihren Kindern die Internetnutzung verbieten. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1858, 372, 'Eltern sollten kontrollieren, mit wem ihre Kinder Umgang haben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1863, 373, 'Eine große Familie oder gute Freunde – was ist wichtiger? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1868, 374, 'Eltern geben ihren Kindern Geld für gute Noten. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1873, 375, 'Familienmitglieder sind unsere besten Freunde. Stimmen Sie zu? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1878, 376, 'Ist es gut, mit Freunden oder Familienmitgliedern zusammenzuarbeiten? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1883, 377, 'Sind Haustiere wichtig für das Wohlbefinden älterer Menschen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1888, 378, 'Freundlichkeit sorgt immer dafür, dass man gehört und respektiert wird. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1893, 379, 'Man kann auch als Single glücklich sein. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1898, 380, 'Allein zu leben ist einfacher als mit der Familie zu leben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1903, 381, 'Finden Sie, dass es einfacher und angenehmer ist, allein zu leben als mit der Familie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1908, 382, 'Glauben Sie, dass es einfacher ist, allein zu leben als mit der Familie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1913, 383, 'Manche junge Erwachsene in Kanada wohnen lieber weiterhin bei ihren Eltern, weil sie sich dort wohlfühlen. Wie sehen Sie diese Situation?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1918, 384, 'Macht Geld glücklich? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1923, 385, 'Sollten Eltern ihren Kindern erlauben, soziale Netzwerke zu nutzen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1928, 386, 'Sollten Eltern ihre Kinder das Internet nutzen lassen, ohne sich Sorgen zu machen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1933, 387, 'Nach dem 25. Lebensjahr bei den Eltern zu wohnen kann praktisch sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1938, 388, 'Ist die Bedeutung von Haustieren in unserer Gesellschaft übertrieben? Begründen Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1943, 389, 'Manche meinen, dass zwei sehr unterschiedliche Menschen nie lebenslange Freunde sein können. Stimmen Sie zu? Begründen Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1948, 390, 'Glauben Sie, dass Freundlichkeit wirklich hilft, Respekt zu bekommen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1953, 391, 'Verhindert das Single-Dasein, glücklich zu sein? Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1958, 392, 'Ist es besser, eine große Familie zu haben oder enge Freunde? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1963, 393, 'Ist es besser, eine große Familie zu haben oder sich auf ein paar sehr enge Freunde zu verlassen? Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1968, 394, 'Heutzutage entscheiden sich manche Menschen dafür, keine Kinder zu bekommen. Wie stehen Sie zu dieser Entscheidung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1973, 395, 'Ist es gut für die Gesellschaft, wenn ältere Menschen arbeiten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1978, 396, 'Ist es Ihrer Meinung nach gut für die Gesellschaft, wenn ältere Menschen arbeiten? Erklären Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1983, 397, 'Ist das Leben in der Stadt für ältere Menschen einfacher als das Leben auf dem Land? Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1988, 398, 'Ist es besser, von einer großen Familie oder von engen, treuen Freunden umgeben zu sein? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1993, 399, 'Ist es Ihrer Meinung nach besser, eine große Familie zu haben oder starke Freundschaften? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1998, 400, 'Glauben Sie, dass Freundlichkeit immer Aufmerksamkeit und Respekt garantiert?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2003, 401, 'Glauben Sie, dass man als Single glücklich sein kann?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2008, 402, 'Garantiert Freundlichkeit immer, dass man gehört und respektiert wird? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2013, 403, 'Kann man sich glücklich fühlen, wenn man Single bleibt? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2018, 404, 'Hat die Familie Ihrer Meinung nach den wichtigsten Platz im Leben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2023, 405, 'Glauben Sie, dass man die Anweisungen des Vorgesetzten bei der Arbeit immer befolgen sollte? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2028, 406, 'Verringern Sozialleistungen Ihrer Meinung nach den Zusammenhalt innerhalb der Familie? Erklären Sie.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2033, 407, 'Sollten Eltern ihren Kindern erlauben, in sozialen Netzwerken zu sein? Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2038, 408, 'Manche meinen, sehr unterschiedliche Menschen können keine dauerhafte Freundschaft aufrechterhalten. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2043, 409, 'Ältere Menschen geben oft nützliche Ratschläge. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2048, 410, 'Immer mehr Menschen entscheiden sich für eine vegetarische Ernährung. Was halten Sie davon?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2053, 411, 'Für ältere Menschen ist es leichter, in der Stadt zu leben als auf dem Land. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2058, 412, 'Das Leben in der Stadt ist stressiger als das Leben auf dem Land. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2063, 413, 'Viele Zeitschriften geben Tipps zum Abnehmen. Sind Sie dafür oder dagegen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2068, 414, 'Wie finden Sie die Ernährung in Ihrem Land?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2073, 415, 'Glauben Sie, der Staat sollte den Verkauf von Tabak und Alkohol verbieten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2078, 416, 'Um gesund zu bleiben, sollte man aufhören, Fleisch zu essen. Was halten Sie von dieser Aussage?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2083, 417, 'Wie kann man Menschen Ihrer Meinung nach dazu motivieren, mehr Sport zu treiben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2088, 418, 'Manche finden, Sportler verdienen zu viel Geld. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2093, 419, 'Heutzutage wollen alle gut aussehen. Was denken Sie über Schönheit?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2098, 420, 'Heutzutage wollen alle jung bleiben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2103, 421, 'Sollte man den Autoverkehr in Städten verbieten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2108, 422, 'Bio-Produkte sind nur etwas für die Reichsten. Stimmen Sie zu? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2113, 423, 'Stress wirkt anregend. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2118, 424, 'Stress ist ein guter Antrieb. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2123, 425, 'Stress kann ein guter Antrieb sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2128, 426, 'Immer mehr Menschen lassen Schönheitsoperationen machen, um jung zu bleiben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2133, 427, 'Es ist möglich, ohne Medikamente zu leben. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2138, 428, 'Kann man heutzutage ohne Medikamente auskommen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2143, 429, 'Zu viele Touristen in einer Stadt sind ein Problem für die Bewohner. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2148, 430, 'Für eine bessere Gesundheit: Ist es besser, auf dem Land statt in der Stadt zu leben? Teilen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2153, 431, 'Heutzutage ist das äußere Erscheinungsbild sehr wichtig. Wie sehen Sie die Bedeutung von Schönheit in der heutigen Gesellschaft?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2158, 432, 'Wie könnte man mehr Menschen dazu bringen, Sport zu treiben? Teilen Sie Ihre Ideen.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2163, 433, 'Sollte man auf Fleisch verzichten, um gesund zu bleiben? Teilen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2168, 434, 'Auf Fleisch zu verzichten ist notwendig, um gesund zu bleiben. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2173, 435, 'Immer mehr Menschen werden Vegetarier. Was halten Sie von dieser Ernährungsweise?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2178, 436, 'Viele Menschen greifen zu Schönheitsoperationen, um jünger auszusehen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2183, 437, 'Ist es Ihrer Meinung nach wichtig, dass ein Unternehmen das Wohlbefinden seiner Mitarbeiter priorisiert, um effektiv zu sein?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2188, 438, 'Welche Maßnahmen könnte man ergreifen, um Menschen zu mehr Sport zu motivieren?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2193, 439, 'Sollten öffentliche Verkehrsmittel in Großstädten für alle kostenlos sein?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2198, 440, 'Erfordert gute Gesundheit, nur Bio-Produkte zu konsumieren? Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2203, 441, 'Ist es sinnvoll, nach 50 noch mit Sport anzufangen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2208, 442, 'Finden Sie, dass das Leben in der Stadt stressiger ist als das Leben auf dem Land? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2213, 443, 'Haben Menschen mit Behinderung Ihrer Meinung nach einen ausreichenden Platz in der Gesellschaft? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2218, 444, 'Ist das Wichtigste für die Gesundheit, sich gut zu ernähren? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2223, 445, 'Manche sagen, das Landleben sei gesünder als das Stadtleben. Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2228, 446, 'Kann man ohne Medikamente leben? Teilen Sie diese Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2233, 447, 'Kann Stress zu einem Motivationsfaktor werden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2238, 448, 'Um den Planeten zu schützen, sollten öffentliche Verkehrsmittel kostenlos sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2243, 449, 'Sollten öffentliche Verkehrsmittel kostenlos sein?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2248, 450, 'Die Entwicklung des Tourismus steht im Widerspruch zum Umweltschutz. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2253, 451, 'Ist es wichtig, erneuerbare Energien auszubauen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2258, 452, 'Es ist notwendig, den Autoverkehr in der Stadt zu begrenzen. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2263, 453, 'Glauben Sie, dass man heute ohne Auto leben kann?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2268, 454, 'Sollten Autos in Innenstädten verboten werden? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2273, 455, 'Was halten Sie vom Leben ohne Auto?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2278, 456, 'Heutzutage ist es möglich, ohne Auto zu leben. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2283, 457, 'Manche Menschen leben lieber ohne Auto. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2288, 458, 'Wasser- und Stromsparen: Diskutieren Sie Strategien, um den Wasser- und Stromverbrauch im Haushalt zu senken, sowie die damit verbundenen ökologischen und wirtschaftlichen Vorteile.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2293, 459, 'Sollten öffentliche Verkehrsmittel kostenlos sein, um die Umwelt zu schützen und die Verschmutzung zu verringern? Begründen Sie Ihre Antwort.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2298, 460, 'Sollten Regierungen Flugreisen begrenzen, um die Umweltverschmutzung zu bekämpfen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2303, 461, 'Ist es wichtig, dass öffentliche Verkehrsmittel zum Schutz der Umwelt kostenlos sind?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2308, 462, 'Heutzutage ist Aussehen für viele Menschen wichtig. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2313, 463, 'Sollte man lokal und saisonal einkaufen, um den Planeten zu schützen? Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2318, 464, 'Glauben Sie, dass einfache Alltagsaktionen wirklich einen Einfluss auf den Schutz des Planeten haben können? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2323, 465, 'Glauben Sie, dass es in der heutigen Welt möglich ist, ohne Auto zu leben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2328, 466, 'Man sollte den Autoverkehr in den Städten reduzieren. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2333, 467, 'Sollten wir Ihrer Meinung nach alle vom Aussterben bedrohten Tiere schützen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2338, 468, 'Was halten Sie von den Maßnahmen in Ihrem Land zur Verringerung der Umweltverschmutzung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2343, 469, 'Viele sagen heute, man könne ohne Technologie nicht mehr leben. Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2348, 470, 'Sollten die Behörden Flugreisen einschränken, um die Umwelt zu schützen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2353, 471, 'Heutzutage versuchen viele Menschen, ihr Aussehen zu verbessern. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2358, 472, 'Das Land zu wechseln heißt, die Kultur zu wechseln. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2363, 473, 'Finden Sie Reisen sinnvoll? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2368, 474, 'Sind Reisen Ihrer Meinung nach wirklich nützlich?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2373, 475, 'Reisen macht Sie zu einem besseren Menschen. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2378, 476, 'Weltraumreisen sind zu teuer und nutzlos. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2383, 477, 'Schauen Sie lieber Theaterstücke oder Filme? Erklären Sie warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2388, 478, 'Die Küche ist eine hervorragende Möglichkeit, ein Land bekannt zu machen. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2393, 479, 'Museen sollten für alle kostenlos sein. Begründen Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2398, 480, 'Haben Zoos einen Nutzen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2403, 481, 'Welche Orte oder Aktivitäten würden Sie einem ausländischen Touristen empfehlen, der Ihr Land zum ersten Mal besucht? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2408, 482, 'Englisch ist fürs Reisen ins Ausland unverzichtbar. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2413, 483, 'Aus welchen Gründen sollte ein Land den Tourismus fördern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2418, 484, 'Warum ist es wichtig, den Tourismus in einem Land zu entwickeln?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2423, 485, 'Sollte der Tourismussektor in Ihrem Land noch weiter ausgebaut werden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2428, 486, 'Man kann andere Kulturen kennenlernen, ohne zu reisen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2433, 487, 'Welche Sache ist Ihrer Meinung nach in der heutigen Welt am wichtigsten: das Soziale, das Humanitäre oder das Kulturelle? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2438, 488, 'Tourismus zerstört manche Regionen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2443, 489, 'Tourismus trägt zum Wachstum und zur Entwicklung eines Landes bei. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2448, 490, 'Haben Zooparks einen Nutzen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2453, 491, 'Manche Menschen reisen lieber allein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2458, 492, 'Manche Menschen reisen lieber allein als in einer Gruppe. Welche Vor- und Nachteile hat diese Art zu reisen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2463, 493, 'Manche entscheiden sich dafür, allein statt in einer Gruppe zu reisen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2468, 494, 'Was halten Sie von Menschen, die sich dafür entscheiden, allein zu reisen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2473, 495, 'Welche Orte und Aktivitäten würden Sie einem ausländischen Touristen empfehlen, der Ihr Land zum ersten Mal besucht? Begründen Sie Ihre Auswahl.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2478, 496, 'Sind Reisen unverzichtbar, um sein Wissen und seine persönliche Erfahrung zu bereichern? Begründen Sie Ihren Standpunkt.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2483, 497, 'Was sind Ihrer Meinung nach die Hauptziele der Tourismusentwicklung in einem Land? Welche Vorteile kann sie für die Wirtschaft und die lokale Kultur bringen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2488, 498, 'Wenn man ins Ausland reist, begegnet man oft neuen Kulturen und Lebensweisen. Glauben Sie, dass das unsere Persönlichkeit verändern kann? Erklären Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2493, 499, 'Wie trägt der Tourismus zur Wirtschaft und Entwicklung eines Landes bei?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2498, 500, 'Welche Gründe bewegen ein Land dazu, die Entwicklung des Tourismus zu fördern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2503, 501, 'Sollten kulturelle Aktivitäten wie Museen oder Theater Ihrer Meinung nach kostenlos sein?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2508, 502, 'Eine Reise ins Ausland kann die Persönlichkeit beeinflussen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2513, 503, 'Hat Reisen Ihrer Meinung nach einen echten Nutzen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2518, 504, 'Ist allein zu reisen manchmal besser als mit Begleitung zu reisen? Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2523, 505, 'Gehen Sie lieber ins Theater oder ins Kino? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2528, 506, 'Das Wachstum des Tourismus kann bestimmte Regionen schädigen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2533, 507, 'Glauben Sie, dass Tourismus die Entwicklung in allen Ländern fördern kann? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2538, 508, 'Welche Erlebnisse oder Orte würden Sie jemandem empfehlen, der Ihr Land zum ersten Mal besucht? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2543, 509, 'Welche der großen aktuellen Herausforderungen (humanitär, sozial oder kulturell) sollte Ihrer Meinung nach Priorität haben? Begründen Sie.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2548, 510, 'Ist es wichtig, dass alle Kultur kostenlos genießen können (Museen, Bücher, Aufführungen usw.)?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2553, 511, 'Glauben Sie, dass Menschen heute noch regelmäßig kochen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2558, 512, 'Viele Menschen mögen es nicht, allein zu reisen. Teilen Sie diese Meinung? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2563, 513, 'Warum interessieren sich Menschen für Reisen mit dem Zug, Flugzeug oder Bus (je nach lokalem Kontext)?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2568, 514, 'Sind Reisen Ihrer Meinung nach vorteilhaft? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2573, 515, 'Fänden Sie es besser, wenn Museen, Theater und andere Kulturstätten für die Öffentlichkeit kostenlos wären? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2578, 516, 'Hilft der Tourismus einem Land, sich zu entwickeln und wirtschaftlich voranzukommen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2583, 517, 'Aus Gründen der Gleichberechtigung haben manche Regierungen 50% Männer und 50% Frauen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2588, 518, 'In ihrer Freizeit engagieren sich manche Menschen in Vereinen oder Organisationen, um anderen zu helfen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2593, 519, 'Finden Sie es wichtig, einen Tag den Rechten der Frauen zu widmen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2598, 520, 'Halten Sie es für notwendig, einen Tag für die Rechte der Frauen vorzusehen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2603, 521, 'Der Staat kann nicht alles kontrollieren. Stimmen Sie zu? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2608, 522, 'Gibt es Ihrer Meinung nach Grenzen der Meinungsfreiheit?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2613, 523, 'Haben Prominente Ihrer Meinung nach einen Platz in der Politik?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2618, 524, 'Manche Menschen interessieren sich lieber nicht für Politik. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2623, 525, 'Manche Menschen entscheiden sich, sich nicht für Politik zu interessieren. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2628, 526, 'Prominente sollten sich stärker am öffentlichen Leben beteiligen. Was halten Sie von dieser Aussage?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2633, 527, 'Manche Menschen entscheiden sich, sich nicht für Politik zu interessieren. Was halten Sie von dieser Haltung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2638, 528, 'Einige Regierungen setzen auf eine gleichmäßige Aufteilung von Männern und Frauen, um Gleichberechtigung zu gewährleisten. Wie sehen Sie diesen Ansatz?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2643, 529, 'Einige Regierungen führen eine Männer-Frauen-Parität in der Politik ein, um Gleichberechtigung zu gewährleisten. Was halten Sie von dieser Maßnahme?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2648, 530, 'Sollte medizinische Versorgung für alle kostenlos sein?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2653, 531, 'Glauben Sie, dass der Staat Grenzen in seiner Kontrolle hat? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2658, 532, 'Was halten Sie von Menschen, die ihre Freizeit für ehrenamtliche Arbeit nutzen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2663, 533, 'Manche Menschen investieren ihre Freizeit in ehrenamtliche Arbeit. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2668, 534, 'Warum verfolgen manche Menschen Politik nicht? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2673, 535, 'Sollte es Ihrer Meinung nach einen Tag geben, der der Verteidigung der Rechte der Frauen gewidmet ist? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2678, 536, 'Sollte der Staat kostenlose Gesundheitsversorgung für die Bürger gewährleisten? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2683, 537, 'Um Gleichberechtigung zu fördern, schreiben manche Länder Geschlechterparität in der Politik vor. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2688, 538, 'Bio-Produkte zu konsumieren ist sinnvoll. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2693, 539, 'Um viel Geld zu verdienen, ist es wichtig, studiert zu haben. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2698, 540, 'Ist es möglich, alle Einkäufe online zu erledigen? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2703, 541, 'Was halten Sie von den Konsumgewohnheiten in reichen Ländern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2708, 542, 'In Supermärkten gibt es immer mehr Bio-Produkte. Ist das Ihrer Meinung nach eine gute Sache?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2713, 543, 'Man muss studieren, um viel Geld zu verdienen. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2718, 544, 'Kann man Ihrer Meinung nach wirtschaftliche Entwicklung und Umweltschutz miteinander vereinbaren? Erklären Sie Ihre Ansicht.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2723, 545, 'Muss man Ihrer Meinung nach lange studieren, um ein hohes Gehalt zu verdienen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2728, 546, 'Um die Welt zu verstehen, muss man sich jeden Tag informieren. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2733, 547, 'Um die Welt zu verstehen: Muss man sich ständig informieren? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2738, 548, 'Man braucht keine Freunde, um glücklich zu sein. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2743, 549, 'Was ist Ihrer Meinung nach das ideale Alter, um auszuwandern? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2748, 550, 'Wenn jemand sein Land verlässt, um anderswo zu leben, liegt das oft daran, dass er keine andere Wahl hat. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2753, 551, 'Kann man heutzutage ohne Fernsehen leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2758, 552, 'Warum interessieren sich Menschen Ihrer Meinung nach so sehr für Prominente?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2763, 553, 'Sind Hausarbeiten in unserem Alltag wichtig?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2768, 554, 'Die meisten Menschen wollen jünger wirken als sie sind. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2773, 555, 'Essgewohnheiten verändern sich im Laufe des Lebens. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2778, 556, 'Heutzutage sind Bücher nutzlos geworden. Stimmen Sie zu?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2783, 557, 'Glauben Sie, dass man in der heutigen Welt ohne Technologie leben kann? Erklären Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2788, 558, 'Ist es wichtig, sich regelmäßig zu informieren, um die Welt um uns herum besser zu verstehen? Erklären Sie Ihre Meinung.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2793, 559, 'Warum sind Menschen so fasziniert vom Leben der Stars? Ist das nur Neugier oder hat es einen größeren Einfluss auf die Gesellschaft?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2798, 560, 'Welche Rolle spielt Kleidung in unseren heutigen Gesellschaften?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2803, 561, 'Glauben Sie, dass zwei sehr unterschiedliche Menschen ihr Leben lang Freunde bleiben können? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2808, 562, 'Ist Lesen unverzichtbar, um gebildet zu sein? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2813, 563, 'Sollte die Meinungsfreiheit begrenzt werden? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2818, 564, 'Glauben Sie, dass man ein Land entdecken kann, ohne seine Sprache zu kennen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2823, 565, 'Warum fühlen sich Menschen Ihrer Meinung nach so stark vom Leben der Prominenten angezogen?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2828, 566, 'Warum interessieren sich Menschen Ihrer Meinung nach so sehr für das Leben von Prominenten?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2833, 567, 'Ist es wichtig, täglich informiert zu sein, um die Ereignisse in der Welt besser zu analysieren?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2838, 568, 'Ist es wirklich möglich, seine Essgewohnheiten als Erwachsener zu ändern? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2843, 569, 'Kann man ein Land allein durch das Lesen von Büchern kennenlernen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2848, 570, 'Glauben Sie, dass sich unsere Essgewohnheiten im Laufe der Jahre verändern?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2853, 571, 'Mehrere Sprachen zu beherrschen ist heutzutage sehr nützlich. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2858, 572, 'Wenn man ein Land besucht, interessiert man sich auch für seine Künstler. Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2863, 573, 'Verbessern Kameras im öffentlichen Raum wirklich die Sicherheit? Was denken Sie?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2868, 574, 'Hat Kleidung Einfluss auf das tägliche Leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2873, 575, 'Glauben Sie, dass es kompliziert ist, sich daran zu gewöhnen, in einem anderen Land zu leben? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2878, 576, 'Welche Gründe können jemanden dazu bringen, sich in einer humanitären Aktion zu engagieren?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2883, 577, 'Kann man sich auf medizinische Termine aus der Ferne verlassen? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2888, 578, 'Gibt es Berufe, die nützlicher sind als andere? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2893, 579, 'Ist Lesen Ihrer Meinung nach eine sinnlose Tätigkeit? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2898, 580, 'Glauben Sie, dass man erfüllt sein kann, wenn man allein lebt? Warum?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2903, 581, 'Haben Bücher Ihrer Meinung nach in der heutigen Gesellschaft an Nutzen verloren?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2908, 582, 'Ist es für einen Einwanderer wichtig, das Aufnahmeland zu kennen? Erklären Sie warum.', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2913, 583, 'Was suchen Menschen, wenn sie sich entscheiden, in einem anderen Land zu leben?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2918, 584, 'Haustiere nehmen in unserem sozialen Leben zu viel Platz ein. Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2923, 585, 'Sollte die gesamte medizinische Versorgung für alle kostenlos sein? Was ist Ihre Meinung?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2928, 586, 'Glauben Sie, dass Kleidung in der modernen Gesellschaft wichtig ist?', '', 'de');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (173, 1, '¿En qué tipo de acción social o comunitaria te gustaría participar?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (174, 2, 'A algunas personas les cuesta adaptarse a la vida en un país extranjero. ¿Qué opinas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (175, 3, 'No hay edad para aprender o estudiar. ¿Estás de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (176, 4, '¿Quién debería cuidar a las personas mayores: los ciudadanos o el Estado? ¿Qué opinas del compromiso cívico?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (177, 5, '¿Crees que las personas mayores son más pesimistas que los jóvenes? ¿Eres optimista respecto a las nuevas generaciones?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (178, 6, '¿Es posible ser amigo de alguien con creencias completamente distintas a las tuyas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (179, 7, '¿Es fácil hacer nuevos amigos en el país de acogida?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (180, 8, 'Viajar te hace mejor persona. ¿Qué piensas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (181, 9, 'Menús vegetarianos: ¿estás a favor o en contra?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (182, 10, 'Los consejos para adelgazar en las revistas: ¿te parecen útiles o no?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (183, 11, 'El transporte público en las ciudades debería ser gratuito. ¿Te parece una buena idea?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (184, 12, 'Para disfrutar de verdad la vida, ¿deberíamos trabajar menos? ¿Qué opinas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (185, 13, '¿Deberían los niños tener un teléfono móvil?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (186, 14, '¿Prefieres vivir en la ciudad o en el campo? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (187, 15, 'Viajar es una actividad reservada solo para la gente rica. ¿Estás de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (188, 16, 'Todo el mundo puede reducir sus residuos. ¿Qué piensas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (189, 17, '¿Las profesiones artísticas son “trabajos de verdad”? ¿Cuál es tu opinión?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (190, 18, '¿Las personas mayores dan siempre buenos consejos?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (191, 19, '¿Las redes sociales facilitan hacer nuevos amigos?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (192, 20, 'Emigrar a Canadá: ¿qué opinas al respecto?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (193, 21, 'Juegos de azar y apuestas: ¿qué opinas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (194, 22, '¿Las personas mayores necesitan una mascota?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (195, 23, 'Usar el móvil en el trabajo: ¿qué te parece?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (196, 24, '¿Los padres deberían educar a niñas y niños de la misma manera?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (197, 25, '¿El papel principal de la escuela es solo enseñar el programa académico?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (198, 26, '¿Leer es esencial para tener cultura y comprender un país?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (199, 27, 'Cuando la gente deja su país para vivir en otro lugar, ¿siempre es por necesidad?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (200, 28, '¿La libertad de expresión debería tener límites?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (201, 29, '¿De verdad se puede conocer un país sin hablar su idioma?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (202, 30, '¿Hace falta ganar mucho dinero para disfrutar de la vida?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (203, 31, '¿Ha cambiado Internet el comportamiento en el trabajo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (204, 32, '¿Qué tipo de medio prefieres para informarte y por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (205, 33, 'Para vivir bien en un país extranjero, ¿es necesario relacionarse con la gente local?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (206, 34, 'Al vivir en el extranjero, ¿los padres deberían hablar con sus hijos en el idioma del país o en su lengua materna?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (207, 35, '¿Se puede desarrollar la economía y a la vez proteger el medio ambiente?', '', 'es');
