insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (689, 138, '¿Qué le parece la idea de trabajar hasta los 70 años?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (694, 139, '¿Cree que trabajar hasta los 70 años es una buena idea?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (699, 140, '¿Prefiere trabajar bajo la responsabilidad de un hombre o de una mujer? ¿Por qué?', '', 'es');
