insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (784, 157, 'Elección de la vestimenta: debata la importancia de la ropa en un contexto profesional, especialmente con el teletrabajo.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (789, 158, '¿Cree que una empresa debería priorizar el bienestar de sus empleados para asegurar su buen funcionamiento? Justifique su punto de vista.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (794, 159, 'Hoy en día, los estudios a menudo se consideran esenciales para encontrar trabajo. Comparta su opinión sobre esta afirmación.', '', 'es');
