insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1384, 277, '¿Debe impedirse que los niños usen un teléfono?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1389, 278, 'El papel principal de la escuela es enseñar materias académicas. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1394, 279, '¿Cree que el rendimiento escolar influye en el éxito en la vida?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1399, 280, 'En su opinión, ¿los adolescentes realmente necesitan su propio teléfono?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1404, 281, '¿Cree que es aceptable no querer tener hijos?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1409, 282, '¿Pueden los jóvenes aprender fácilmente una lengua extranjera? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1414, 283, 'En su opinión, ¿los jóvenes consiguen dominar fácilmente una lengua extranjera? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1419, 284, '¿Qué materias debería ofrecer la escuela para hacer las clases más interesantes para los alumnos? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1424, 285, '¿Qué clase prefería en la escuela y por qué le gustaba?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1429, 286, '¿Cuál era su materia favorita en la escuela y por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1434, 287, 'En su opinión, ¿qué materias deberían enseñarse más en la escuela y por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1439, 288, '¿La diversidad social y cultural en la escuela fomenta la tolerancia entre los alumnos? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1444, 289, '¿Es necesario que las organizaciones ofrezcan oportunidades de aprendizaje regulares a su personal? ¿Es beneficioso este acceso para el individuo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1449, 290, '¿Qué piensa de las personas que deciden no ver nunca la televisión?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1454, 291, '¿Es mejor aprender una lengua extranjera desde la infancia? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1459, 292, '¿La diversidad en las escuelas ayuda a que todos los alumnos se desarrollen mejor?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1464, 293, '¿Deberían las universidades recibir más financiación? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1469, 294, '¿Qué lecciones o materias deberían tener más espacio en los programas escolares? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1474, 295, 'En su opinión, ¿hace falta autoridad para educar correctamente a un niño? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1479, 296, '¿Es necesario tener un nivel de estudios alto para tener éxito en la vida? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1484, 297, 'Algunos jóvenes canadienses eligen vivir con sus padres porque se sienten cómodos. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1489, 298, '¿La escuela ofrece las mismas oportunidades a todos los alumnos? Comparta su opinión.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1494, 299, '¿Cree que los videojuegos pueden desempeñar un papel en el desarrollo de un niño?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1499, 300, '¿La televisión es una buena herramienta para aprender? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1504, 301, 'En su opinión, ¿qué debería enseñar la escuela para reforzar la motivación y el interés de los alumnos? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1509, 302, '¿Qué materia le gusta más en la escuela? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1514, 303, '¿Cree que es importante que niñas y niños reciban la misma educación? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1519, 304, '¿Debería enseñarse la tecnología en la escuela desde una edad temprana? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1524, 305, '¿Cree que la autoridad es indispensable para educar bien a los niños? Justifique su punto de vista.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1529, 306, 'En su opinión, ¿es necesario estudiar durante mucho tiempo para tener éxito en la vida?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1534, 307, 'La educación ambiental debería empezar muy temprano en los niños. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1539, 308, '¿La mayoría de la gente intenta parecer más joven de lo que es? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1544, 309, '¿Los videojuegos constituyen un peligro para los jugadores? Explique por qué.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1549, 310, '¿Cree que las escuelas deberían valorar más las actividades artísticas (música, teatro, artes visuales, etc.)? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1554, 311, 'En su opinión, ¿podemos vivir sin Internet? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1559, 312, 'Usar las redes sociales es una pérdida de tiempo. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1564, 313, 'Utilizamos dispositivos electrónicos a diario (ordenadores, smartphones, tabletas, etc.). En su opinión, ¿qué riesgos están asociados a su uso?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1569, 314, 'Algunos economistas creen que las nuevas tecnologías destruirán empleos. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1574, 315, 'Con Internet, vivimos mejor. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1579, 316, 'En su opinión, ¿deberían prohibirse los teléfonos móviles en la escuela? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1584, 317, 'En su opinión, ¿debería prohibirse a los niños usar teléfonos móviles? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1589, 318, 'Gracias a Internet estamos mejor informados. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1594, 319, 'Los teléfonos móviles facilitan la comunicación. ¿Está de acuerdo? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1599, 320, 'Internet nos hace felices. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1604, 321, 'Hoy en día, la gente casi ya no se envía correo (tarjetas de felicitación, cartas de amor, etc.). ¿Es algo que lamentar?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1609, 322, 'En su opinión, ¿un teléfono móvil es indispensable?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1614, 323, 'Un teléfono móvil es indispensable en la vida cotidiana. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1619, 324, 'Es fácil prescindir del teléfono móvil. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1624, 325, 'Algunas personas se niegan a ver las noticias en la televisión. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1629, 326, 'Internet vuelve a la gente solitaria. ¿Qué piensa de esta afirmación?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1634, 327, 'Algunas personas prefieren vivir sin tecnología (internet, ordenador, teléfono). ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1639, 328, 'Con Internet, el mundo se ha convertido en un pueblo. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1644, 329, 'Los informativos de televisión no deberían emitir imágenes violentas. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1649, 330, '¿Está de acuerdo con la idea de que los informativos de televisión deberían evitar difundir imágenes violentas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1654, 331, '¿Las amistades que se hacen en línea son tan sólidas como los lazos familiares? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1659, 332, 'Las nuevas tecnologías tienen un impacto positivo en nuestra sociedad. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1664, 333, 'Hoy en día, muchas personas cambian de teléfono móvil con regularidad. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1669, 334, 'Debata cómo las cámaras de vigilancia en lugares públicos afectan a la seguridad y a la privacidad.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1674, 335, '¿Cree que Internet contribuye realmente a la felicidad de la gente? Justifique su respuesta.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1679, 336, 'Gracias a Internet, ¿estamos mejor informados que antes? Comparta su opinión.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1684, 337, '¿Pueden las amistades virtuales en Internet ser tan sólidas como los lazos familiares? Explique su punto de vista.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1689, 338, '¿Cree que las redes sociales son una pérdida de tiempo o, por el contrario, una herramienta útil? Justifique su punto de vista.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1694, 339, 'Con el desarrollo de Internet, las fronteras parecen desvanecerse, convirtiendo el mundo en una «aldea global». ¿Hasta qué punto está de acuerdo con esta visión?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1699, 340, '¿Deberían los medios limitar la difusión de imágenes violentas en los informativos? ¿Qué cuestiones éticas e informativas están en juego?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1704, 341, 'El uso diario de dispositivos electrónicos conlleva ciertos riesgos. En su opinión, ¿cuáles son los principales peligros asociados a su uso?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1709, 342, 'Con las herramientas digitales, muchas tareas cotidianas se han vuelto más rápidas de realizar. ¿Está de acuerdo? Dé ejemplos para apoyar su respuesta.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1714, 343, '¿Cree que Internet mejora nuestra vida cotidiana?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1719, 344, 'En su opinión, ¿cuáles son los impactos y los posibles peligros del uso diario de dispositivos electrónicos como teléfonos, ordenadores y tabletas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1724, 345, 'A menudo se dice que Internet ha hecho el mundo más conectado, como un pequeño pueblo. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1729, 346, 'En su opinión, ¿Internet hace la vida más fácil?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1734, 347, 'Hoy en día, intercambiar cartas o tarjetas se ha vuelto muy raro. ¿Cree que es un cambio lamentable?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1739, 348, '¿Cree que las herramientas digitales nos ayudan a gestionar mejor nuestro tiempo en el día a día? Explique.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1744, 349, '¿Cree que las nuevas tecnologías podrían reemplazar el trabajo humano en el futuro?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1749, 350, '¿Internet tiene un impacto positivo en la felicidad de las personas? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1754, 351, '¿Se puede realmente comprar todo por Internet? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1759, 352, '¿Cree que usar las redes sociales dificulta concentrarse en lo esencial? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1764, 353, '¿Cree que Internet realmente ha acercado a las personas en todo el mundo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1769, 354, '¿Cree que deberíamos proteger al público —especialmente a los jóvenes— de las imágenes violentas en las noticias?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1774, 355, '¿Las relaciones creadas en Internet son tan fuertes como los lazos familiares? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1779, 356, '¿Cree que los niños pasan demasiado tiempo frente a pantallas (TV, teléfono, ordenador, tableta)? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1784, 357, '¿Cree que hoy podemos vivir sin Internet? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1789, 358, 'Algunas personas prefieren dejar de ver las noticias en la televisión. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1794, 359, '¿El uso de Internet puede hacer que las personas se sientan solas? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1799, 360, '¿Cree que todavía podemos prescindir del teléfono móvil? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1804, 361, '¿Las amistades en línea son tan sólidas como los lazos familiares? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1809, 362, '¿El uso de redes sociales o aplicaciones hace a la gente menos activa y dinámica? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1814, 363, 'Hoy en día, la gente casi ya no intercambia cartas o tarjetas (de felicitación, de amor, etc.). ¿Cree que es una pena?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1819, 364, '¿Es importante aprender a usar las nuevas tecnologías (internet, redes sociales, etc.) desde la infancia? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1824, 365, '¿Nuestro consumo de cosas como ropa y teléfonos es excesivo? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1829, 366, 'En el futuro, gracias a las nuevas tecnologías, ya no será necesario trabajar. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1834, 367, '¿Qué impactos y riesgos puede tener el uso habitual de teléfonos, ordenadores y tabletas?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1839, 368, 'Las herramientas digitales ayudan a ahorrar tiempo en la vida cotidiana. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1844, 369, 'Gracias a las redes sociales, es más fácil conocer gente y hacer amigos. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1849, 370, 'Vivir solo/a es difícil. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1854, 371, 'En casa, los padres deberían prohibir a sus hijos usar Internet. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1859, 372, 'Los padres deben controlar con quién pasan el tiempo sus hijos. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1864, 373, '¿Una familia grande o buenos amigos? ¿Qué es más importante? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1869, 374, 'Los padres dan dinero a sus hijos por las buenas notas. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1874, 375, 'Los miembros de la familia son nuestros mejores amigos. ¿Está de acuerdo? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1879, 376, '¿Es buena idea trabajar con amigos o familiares? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1884, 377, '¿Las mascotas son esenciales para el bienestar de las personas mayores? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1889, 378, 'La amabilidad siempre ayuda a que lo escuchen y lo respeten. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1894, 379, 'Se puede ser feliz siendo soltero/a. ¿Está de acuerdo?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1899, 380, 'Es más fácil vivir solo/a que vivir en familia. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1904, 381, 'En su opinión, ¿es más simple y agradable vivir solo/a que vivir en familia?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1909, 382, '¿Cree que es más simple vivir solo/a que vivir en familia?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1914, 383, 'Algunos jóvenes adultos canadienses prefieren seguir viviendo con sus padres porque se sienten bien allí. ¿Qué opina de esta situación?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1919, 384, '¿El dinero compra la felicidad? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1924, 385, '¿Deberían los padres dejar que sus hijos usen las redes sociales? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1929, 386, '¿Deberían los padres dejar que los niños usen Internet sin miedo? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1934, 387, 'Vivir con sus padres después de los 25 puede ser práctico. ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1939, 388, '¿Está exagerado el lugar que ocupan las mascotas en nuestra sociedad? Justifique su punto de vista.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1944, 389, 'Algunas personas piensan que dos individuos muy diferentes nunca pueden ser amigos para toda la vida. ¿Está de acuerdo? Argumente su punto de vista.', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1949, 390, '¿Cree que la amabilidad realmente ayuda a ganarse el respeto? ¿Por qué?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1954, 391, '¿Ser soltero/a impide ser feliz? ¿Cuál es su opinión?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1959, 392, '¿Es mejor tener una familia grande o amigos cercanos? ¿Qué piensa?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1964, 393, '¿Es mejor tener una familia numerosa o contar con unos pocos amigos muy cercanos? ¿Cuál es su opinión?', '', 'es');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (1969, 394, 'Hoy en día, algunas personas deciden no tener hijos. ¿Qué opina de esa decisión?', '', 'es');
