insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2565, 513, '为什么人们会对乘火车、飞机或大巴旅行感兴趣（视当地情况而定）？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2570, 514, '在您看来，旅行有益吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2575, 515, '如果博物馆、剧院和其他文化场所对公众免费开放会更好吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2580, 516, '旅游业是否能帮助一个国家经济发展与进步？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2585, 517, '出于平等原因，有些政府由50%男性和50%女性组成。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2590, 518, '有些人在空闲时间参加志愿组织帮助他人。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2595, 519, '您认为设立一个关注女性权利的日子重要吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2600, 520, '您认为需要专门设立一天关注女性权利吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2605, 521, '国家不可能控制一切。您同意吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2610, 522, '在您看来，言论自由有界限吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2615, 523, '您认为名人适合从政吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2620, 524, '有些人宁愿不关心政治。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2625, 525, '有些人决定不关心政治。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2630, 526, '名人应该更多参与公共生活。您怎么看这句话？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2635, 527, '有些人选择不关心政治。您怎么看这种态度？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2640, 528, '有些政府为了保证平等，实行男女均等分配。您怎么看这种做法？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2645, 529, '有些政府在政治领域推行性别平等比例以保证平等。您怎么看这项措施？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2650, 530, '医疗服务应该对所有人免费吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2655, 531, '您认为国家在控制方面有界限吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2660, 532, '您怎么看那些利用空闲时间做志愿服务的人？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2665, 533, '有些人把空闲时间用来做志愿服务。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2670, 534, '为什么有些人不关注政治？您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2675, 535, '在您看来，是否应该有一天专门用于捍卫女性权利？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2680, 536, '国家应该为公民提供免费的医疗保障吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2685, 537, '为了促进平等，有些国家在政治领域强制推行性别平等比例。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2690, 538, '消费有机产品是有益的。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2695, 539, '要赚很多钱，必须受过良好教育。您同意吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2700, 540, '是否可以把所有购物都放到线上完成？您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2705, 541, '您怎么看富裕国家的消费习惯？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2710, 542, '超市里有机产品越来越多。您觉得这是好事吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2715, 543, '要赚很多钱就得读书。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2720, 544, '您认为经济发展与环境保护可以兼顾吗？请解释您的观点。', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2725, 545, '您认为要拿到高薪，需要长期学习吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2730, 546, '为了理解世界，我们需要每天获取信息。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2735, 547, '为了理解世界，是否必须一直保持信息更新？您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2740, 548, '不需要朋友也能幸福。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2745, 549, '您认为移民的理想年龄是多少？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2750, 550, '当一个人离开祖国去别处生活，往往是因为别无选择。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2755, 551, '如今可以不看电视生活吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2760, 552, '在您看来，人们为什么对名人如此感兴趣？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2765, 553, '家务在日常生活中重要吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2770, 554, '大多数人都想显得比实际年龄更年轻。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2775, 555, '饮食习惯会随着人生阶段而变化。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2780, 556, '如今，书已经变得没用了。您同意吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2785, 557, '您认为在当今世界不靠科技也能生活吗？请解释您的看法。', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2790, 558, '为了更好理解我们周围的世界，是否必须经常获取信息？请说明您的观点。', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2795, 559, '人们为何迷恋明星的生活？这只是好奇，还是对社会有更深影响？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2800, 560, '在当今社会，穿着扮演什么角色？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2805, 561, '您认为两个差异很大的人能做一辈子朋友吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2810, 562, '阅读对于成为有文化的人是不可或缺的吗？您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2815, 563, '您认为言论自由应该受到限制吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2820, 564, '您认为不懂当地语言也能了解一个国家吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2825, 565, '在您看来，人们为什么如此被名人的生活吸引？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2830, 566, '在您看来，人们为什么这么关注名人的生活？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2835, 567, '每天了解信息对更好分析世界事件是否必不可少？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2840, 568, '您觉得成年人真的可以改变自己的饮食习惯吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2845, 569, '仅仅通过读书就能了解一个国家吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2850, 570, '您认为我们的饮食习惯会随着年份变化吗？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2855, 571, '如今，会多种语言非常有用。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2860, 572, '参观一个国家时，人们也会关注它的艺术家。您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2865, 573, '公共场所的摄像头真的能提高安全性吗？您怎么看？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2870, 574, '穿着会影响日常生活吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2875, 575, '您认为适应在另一个国家生活很难吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2880, 576, '什么原因会促使一个人参与人道主义工作？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2885, 577, '您认为可以依赖远程医疗预约或线上问诊吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2890, 578, '有些职业比其他职业更有用吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2895, 579, '在您看来，阅读是一项无用的活动吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2900, 580, '您认为独自生活也能感到充实吗？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2905, 581, '在您看来，书在当今社会是否已经失去作用？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2910, 582, '对移民来说，了解接收国是否很重要？为什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2915, 583, '人们选择在另一个国家生活时在寻找什么？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2920, 584, '宠物在我们的社交生活中占据的地位太大了。您的看法是？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2925, 585, '所有医疗服务都应该对所有人免费吗？您的看法是？', '', 'zh');
insert into cues.cue_content (cue_content_id, cue_id, title, details, language_code) values (2930, 586, '您认为衣服在现代社会重要吗？', '', 'zh');
